using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Strongly-typed metadata via the generic GetTypeInfo<T>() -----------

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented    = true
};

// Generic overload returns JsonTypeInfo<T> directly – no cast required.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();

Console.WriteLine("=== GetTypeInfo<Person>() ===");
Console.WriteLine($"Type       : {personInfo.Type.Name}");
Console.WriteLine($"Return type: {personInfo.GetType().Name}  (generic)");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized : {json}");
Console.WriteLine();

// --- 2. Probe without throwing via TryGetTypeInfo() -----------------------

Console.WriteLine("=== TryGetTypeInfo – type IS resolvable ===");
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    // Safe downcast to the generic form when you know the type.
    var typed = (JsonTypeInfo<Person>)info!;
    Console.WriteLine($"Got metadata for {typed.Type.Name} ✓");
}

Console.WriteLine();
Console.WriteLine("=== TryGetTypeInfo – type is NOT resolvable ===");

// Use a resolver that knows about nothing → metadata won't be found.
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

if (empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing))
{
    Console.WriteLine("Found metadata (unexpected)");
}
else
{
    Console.WriteLine($"No metadata for Person – handled gracefully, no exception ✓");
}

// --- Supporting types -----------------------------------------------------

record Person(string Name, int Age);

/// <summary>A resolver that intentionally resolves nothing.</summary>
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

